select.if:
SELECT ESNTL_ID uniqId, 'GNR' userSe, MBER_ID userId, MBER_NM userNm,
       MBER_EMAIL_ADRES email, TELNO telno, ZIP zip, ADRES adres, DETAIL_ADRES detailAdres
  FROM TB_GNRL_MBER WHERE ESNTL_ID = #{uniqId}

SELECT ESNTL_ID uniqId, 'USR' userSe, EMPLYR_ID userId, USER_NM userNm,
       EMAIL_ADRES email, MBTLNUM telno, ZIP zip, HOUSE_ADRES adres, DETAIL_ADRES detailAdres
  FROM TB_EMPLYR_INFO WHERE ESNTL_ID = #{uniqId}

SELECT ESNTL_ID uniqId, 'ENT' userSe, ENTRPRS_MBER_ID userId, CMPNY_NM userNm,
       APPLCNT_EMAIL_ADRES email, TELNO telno, ZIP zip, ADRES adres, DETAIL_ADRES detailAdres
  FROM TB_ENTRPRS_MBER WHERE ESNTL_ID = #{uniqId}

update.if:
UPDATE TB_GNRL_MBER
   SET MBER_NM = #{userNm}, MBER_EMAIL_ADRES = #{email}, TELNO = #{telno},
       ZIP = #{zip}, ADRES = #{adres}, DETAIL_ADRES = #{detailAdres},
       LAST_UPDT_PNTTM = now(), LAST_UPDUSR_ID = #{userId}
 WHERE ESNTL_ID = #{uniqId}

UPDATE TB_EMPLYR_INFO
   SET USER_NM = #{userNm}, EMAIL_ADRES = #{email}, MBTLNUM = #{telno},
       ZIP = #{zip}, HOUSE_ADRES = #{adres}, DETAIL_ADRES = #{detailAdres},
       LAST_UPDT_PNTTM = now(), LAST_UPDUSR_ID = #{userId}
 WHERE ESNTL_ID = #{uniqId}

UPDATE TB_ENTRPRS_MBER
   SET CMPNY_NM = #{userNm}, APPLCNT_EMAIL_ADRES = #{email}, TELNO = #{telno},
       ZIP = #{zip}, ADRES = #{adres}, DETAIL_ADRES = #{detailAdres},
       LAST_UPDT_PNTTM = now(), LAST_UPDUSR_ID = #{userId}
 WHERE ESNTL_ID = #{uniqId}
